import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { extractTransactionsFromComplexBlock } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V5 - MODO PROCESSAMENTO INTEGRAL)
 * Este motor aplica as regras de um modelo aprendido sobre o conteúdo real do arquivo.
 * Ajustado para ignorar o limite de visualização (snippet) e focar no conteúdo completo.
 */
export const ContractExecutor = {
    async apply(model: FileModel, normalizedContent: string): Promise<Transaction[]> {
        const extractionMode = model.mapping.extractionMode || 'COLUMNS';

        // FONTES DE DADOS: Prioriza sempre o conteúdo normalizado vindo do upload atual.
        // O snippet do modelo é usado apenas como fallback ou referência estrutural.
        const sourceContent = normalizedContent || model.snippet || "";
        const lines = sourceContent.split(/\r?\n/);

        console.log(`[ContractExecutor:START] Aplicando Modelo: ${model.name} | Linhas Detectadas: ${lines.length}`);

        // --- MODO BLOCO (IA CONTEXTUAL) ---
        if (extractionMode === 'BLOCK') {
            // A IA processa o conteúdo integral enviado (respeitando limites de token do modelo Gemini)
            const aiResults = await extractTransactionsFromComplexBlock(sourceContent);
            const results = (aiResults || []).map((tx: any, idx: number) => ({
                id: `contract-block-${model.id}-${idx}-${Date.now()}`,
                date: tx.date,
                description: tx.description,
                rawDescription: tx.description,
                amount: tx.amount,
                originalAmount: String(tx.amount),
                cleanedDescription: tx.description,
                contributionType: tx.type || 'AUTO',
                paymentMethod: tx.paymentMethod || 'OUTROS'
            }));

            console.log(`[ContractExecutor:DONE] Modo: BLOCK | Extraídas: ${results.length}`);
            return results;
        }

        // --- MODO COLUNAS (MAPEAMENTO RIGOROSO) ---
        const { 
            dateColumnIndex, 
            descriptionColumnIndex, 
            amountColumnIndex, 
            paymentMethodColumnIndex, 
            typeColumnIndex,
            skipRowsStart 
        } = model.mapping;

        const delimiter = model.fingerprint.delimiter || ';';
        const yearAnchor = DateResolver.discoverAnchorYear(sourceContent);
        const transactions: Transaction[] = [];

        lines.forEach((line, index) => {
            // Pula apenas as linhas de cabeçalho definidas no modelo
            if (index < (skipRowsStart || 0)) return;

            const cols = line.split(delimiter);

            // Validação de existência de colunas mínimas conforme o contrato
            if (cols.length > Math.max(dateColumnIndex, descriptionColumnIndex, amountColumnIndex)) {
                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                // Ignora linhas totalmente vazias
                if (!rawDate && !rawDesc && !rawAmount) return;

                const stdAmount = AmountResolver.clean(rawAmount);
                const numericValue = parseFloat(stdAmount);

                // Validação de valor numérico (evita lixo de rodapé)
                if (isNaN(numericValue)) return;

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);

                const finalType = (typeColumnIndex !== undefined && typeColumnIndex !== -1)
                    ? (cols[typeColumnIndex] || 'AUTO').trim().toUpperCase()
                    : 'AUTO';

                const finalForm = (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex !== -1)
                    ? (cols[paymentMethodColumnIndex] || 'OUTROS').trim().toUpperCase()
                    : 'OUTROS';

                transactions.push({
                    id: `contract-col-${model.id}-${index}-${Date.now()}`,
                    date: isoDate || rawDate,
                    description: rawDesc,
                    rawDescription: rawDesc,
                    amount: numericValue,
                    originalAmount: rawAmount,
                    cleanedDescription: rawDesc, 
                    contributionType: finalType,
                    paymentMethod: finalForm
                });
            }
        });

        console.log(`[ContractExecutor:DONE] Modo: COLUMNS | Extraídas: ${transactions.length}`);
        return transactions;
    }
};

import { Transaction, FileModel } from '../types';
import { ContractExecutor } from './engine/ContractExecutor';
import { Fingerprinter } from './processors/Fingerprinter';
import { DateResolver } from './processors/DateResolver';
import { AmountResolver } from './processors/AmountResolver';
import { TypeResolver } from './processors/TypeResolver';

export interface BankStrategy {
    name: string;
    canHandle(filename: string, content: string, models?: FileModel[]): boolean;
    parse(content: string, yearAnchor: number, models?: FileModel[], globalKeywords?: string[]): Transaction[] | Promise<Transaction[]>;
}

/**
 * 🛡️ PIPELINE SOURCE RESOLVER (INTEGRAL V5)
 * Processamento via Modelo Aprendido usando o ContractExecutor.
 */
export const DatabaseModelStrategy: BankStrategy = {
    name: 'Modelo Aprendido',
    canHandle: (filename, content, models) => {
        if (!models || models.length === 0) return false;
        const fileFp = Fingerprinter.generate(content);
        if (!fileFp) return false;

        return models.some(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp.headerHash && m.fingerprint.headerHash !== null) ||
                (m.fingerprint.structuralPattern === fileFp.structuralPattern && m.fingerprint.structuralPattern !== 'UNKNOWN') ||
                (m.fingerprint.canonicalSignature === fileFp.canonicalSignature)
            )
        );
    },
    parse: async (content, yearAnchor, models, globalKeywords = []) => {
        const fileFp = Fingerprinter.generate(content);
        const model = models?.find(m => 
            m.is_active && (
                (m.fingerprint.headerHash === fileFp?.headerHash) || 
                (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                (m.fingerprint.canonicalSignature === fileFp?.canonicalSignature)
            )
        );

        if (!model) return [];

        console.log(`[Pipeline:SOURCE] Aplicando contrato do modelo: ${model.name}`);

        // Delega a execução para o ContractExecutor que agora processa o conteúdo integral
        return await ContractExecutor.apply(model, content);
    }
};

export const GenericStrategy: BankStrategy = {
    name: 'Genérico',
    canHandle: () => true,
    parse: (content, yearAnchor, models, globalKeywords = []) => {
        const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
        if (lines.length === 0) return [];
        const delimiter = Fingerprinter.detectDelimiter(lines[0]);
        const grid = lines.map(l => l.split(delimiter));
        const dateIdx = DateResolver.identifyDateColumn(grid);
        const amountIdx = AmountResolver.identifyAmountColumn(grid, [dateIdx]);
        const nameIdx = TypeResolver.identifyTypeColumn(grid, [dateIdx, amountIdx]);
        const transactions: Transaction[] = [];
        grid.forEach((cols, index) => {
            const rawDate = cols[dateIdx] || '';
            const rawDesc = cols[nameIdx] || cols.join(' ');
            const rawAmount = cols[amountIdx] || '';
            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numVal = parseFloat(stdAmount);
            if (isoDate && !isNaN(numVal) && stdAmount !== "0.00") {
                transactions.push({
                    id: `gen-${index}-${Date.now()}`,
                    date: isoDate,
                    description: rawDesc,
                    rawDescription: rawDesc,
                    amount: numVal,
                    originalAmount: rawAmount,
                    cleanedDescription: rawDesc,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc)
                });
            }
        });
        return transactions;
    }
};

export const StrategyEngine = {
    strategies: [DatabaseModelStrategy, GenericStrategy],
    process: async (filename: string, content: string, models: FileModel[] = [], globalKeywords: string[] = [], overrideModel?: FileModel): Promise<{ transactions: Transaction[], strategyName: string }> => {
        const yearAnchor = DateResolver.discoverAnchorYear(content);

        let targetModel = overrideModel;

        if (!targetModel) {
            const fileFp = Fingerprinter.generate(content);
            targetModel = models.find(m => 
                m.is_active && (
                    (m.fingerprint.headerHash === fileFp?.headerHash && m.fingerprint.headerHash !== null) ||
                    (m.fingerprint.structuralPattern === fileFp?.structuralPattern) ||
                    (m.fingerprint.canonicalSignature === fileFp?.canonicalSignature)
                )
            );
        }

        if (targetModel) {
            const txs = await DatabaseModelStrategy.parse(content, yearAnchor, [targetModel], globalKeywords);
            return { transactions: txs, strategyName: targetModel.name };
        }

        const genResult = GenericStrategy.parse(content, yearAnchor, models, globalKeywords) as Transaction[];
        return { transactions: genResult, strategyName: 'Genérico' };
    }
};

import { useEffect, useCallback, useRef } from 'react';
import { Transaction } from '../types';
import { consolidationService } from '../services/ConsolidationService';

interface UseLiveListSyncProps {
    user: any;
    setBankStatementFile: (fn: (prev: any[]) => any[]) => void;
    setSelectedBankIds: (fn: (prev: string[]) => string[]) => void;
    showToast?: (msg: string, type: 'success' | 'error') => void;
}

export const useLiveListSync = ({
    user,
    setBankStatementFile,
    setSelectedBankIds,
    showToast
}: UseLiveListSyncProps) => {
    // Trava de segurança para impedir múltiplas execuções simultâneas
    const isHydrating = useRef(false);
    const hasHydrated = useRef(false);
    const lastUserId = useRef<string | null>(null);

    // --- HIDRATAÇÃO: Recupera do DB ao iniciar ---
    useEffect(() => {
        // Só executa se tiver usuário, não estiver hidratando e o usuário mudou ou nunca hidratou
        if (!user || isHydrating.current || (hasHydrated.current && lastUserId.current === user.id)) return;

        const hydrate = async () => {
            isHydrating.current = true;
            lastUserId.current = user.id;

            try {
                console.log(`[Lista Viva] Iniciando recuperação de dados para usuário: ${user.id}`);

                // Busca as transações com limite de segurança para evitar Erro 400/Timeout
                const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                if (!dbTransactions || dbTransactions.length === 0) {
                    hasHydrated.current = true;
                    isHydrating.current = false;
                    return;
                }

                const groupedByBank: Record<string, Transaction[]> = {};

                // Processamento otimizado: Limita a 2000 registros para garantir estabilidade da UI
                const safeTransactions = dbTransactions.slice(0, 2000);

                safeTransactions.forEach((t: any) => {
                    const bankId = t.bank_id || 'unknown';
                    const tx: Transaction = {
                        id: t.id,
                        date: t.transaction_date,
                        description: t.description,
                        rawDescription: t.description,
                        amount: t.amount,
                        originalAmount: String(t.amount.toFixed(2)),
                        contributionType: t.type === 'income' ? 'ENTRADA' : 'SAÍDA',
                        cleanedDescription: t.description
                    };
                    if (!groupedByBank[bankId]) groupedByBank[bankId] = [];
                    groupedByBank[bankId].push(tx);
                });

                const restoredFiles = Object.entries(groupedByBank).map(([bankId, txs]) => ({
                    bankId,
                    content: '',
                    fileName: `Lista Viva (Recuperada)`,
                    rawFile: undefined,
                    processedTransactions: txs,
                    isRestored: true
                }));

                // Atualização atômica do estado para evitar múltiplos disparos de render
                setBankStatementFile(() => restoredFiles);
                setSelectedBankIds(() => restoredFiles.map(f => f.bankId));

                hasHydrated.current = true;
                console.log(`[Lista Viva] ${safeTransactions.length} transações restauradas com sucesso.`);
            } catch (err) {
                console.error("[Lista Viva] Erro crítico na hidratação:", err);
            } finally {
                isHydrating.current = false;
            }
        };

        hydrate();
    }, [user, setBankStatementFile, setSelectedBankIds]);

    // --- PERSISTÊNCIA: Helper para salvar novas transações ---
    const persistTransactions = useCallback(async (bankId: string, transactions: Transaction[]) => {
        if (!user || transactions.length === 0) return;
        try {
            // Chunking: Se o lote for muito grande, o Supabase pode dar erro 400.
            // Dividimos em pedaços de 100 para garantir a gravação de 700+ linhas.
            const chunkSize = 100;
            for (let i = 0; i < transactions.length; i += chunkSize) {
                const chunk = transactions.slice(i, i + chunkSize);
                const data = chunk.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id,
                    bank_id: bankId.length > 10 ? bankId : null 
                }));
                await consolidationService.addTransactions(data);
            }
            console.log(`[Lista Viva] ${transactions.length} linhas persistidas remotamente.`);
        } catch (e) {
            console.warn("[Lista Viva] Falha na sincronização remota (Modo Offline)", e);
        }
    }, [user]);

    const clearRemoteList = useCallback(async (bankId?: string) => {
        if (!user) return;
        try {
            await consolidationService.deletePendingTransactions(user.id, bankId);
            // Resetamos a flag para permitir nova hidratação se necessário
            hasHydrated.current = false;
        } catch (e) {
            console.error("[Lista Viva] Erro ao limpar banco remoto:", e);
        }
    }, [user]);

    return { persistTransactions, clearRemoteList };
};

import { supabase } from './supabaseClient';
import { Database } from '../types/supabase';

type ConsolidatedTransactionInsert = Database['public']['Tables']['consolidated_transactions']['Insert'];

export const consolidationService = {
    addTransaction: async (transaction: ConsolidatedTransactionInsert) => {
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert({
                transaction_date: transaction.transaction_date,
                amount: transaction.amount,
                description: transaction.description,
                type: transaction.type,
                pix_key: transaction.pix_key,
                source: transaction.source,
                user_id: transaction.user_id,
                bank_id: transaction.bank_id,
                status: 'pending'
            })
            .select()
            .single();

        if (error) throw error;
        return data;
    },

    addTransactions: async (transactions: ConsolidatedTransactionInsert[]) => {
        if (transactions.length === 0) return [];

        const { data, error } = await supabase
            .from('consolidated_transactions')
            .insert(transactions.map(t => ({
                transaction_date: t.transaction_date,
                amount: t.amount,
                description: t.description,
                type: t.type,
                pix_key: t.pix_key,
                source: t.source,
                user_id: t.user_id,
                bank_id: t.bank_id,
                status: 'pending' as const
            })))
            .select();

        if (error) {
            console.error("Erro no batch insert:", error);
            throw error;
        }
        return data;
    },

    deletePendingTransactions: async (userId: string, bankId?: string) => {
        try {
            let query = supabase
                .from('consolidated_transactions')
                .delete()
                .eq('user_id', userId)
                .eq('status', 'pending');

            if (bankId) {
                query = query.eq('bank_id', bankId);
            }

            const { error } = await query;
            if (error) throw error;
        } catch (error) {
            console.error("[Consolidation] Erro na exclusão:", error);
            throw error;
        }
    },

    getPendingTransactions: async (userId: string) => {
        // Seleção simplificada para evitar overhead de rede e Erro 400
        const { data, error } = await supabase
            .from('consolidated_transactions')
            .select('id, transaction_date, amount, description, type, bank_id')
            .eq('user_id', userId)
            .eq('status', 'pending')
            .order('transaction_date', { ascending: false })
            .limit(3000); // Limite de segurança para performance

        if (error) throw error;
        return data;
    }
};

